SELECT
FROM fit_analysis fa INNER JOIN application_case ac ON ac.id = fa.application_case_id INNER JOIN users ON users.id = ac.user_id LEFT JOIN fit_analysis_gate_result gr ON gr.fit_analysis_id = fa.id LEFT JOIN users reviewer ON reviewer.id = gr.reviewed_by
ORDER BY fa.created_at DESC, fa.id DESC LIMIT #{c.size} OFFSET #{c.offset}

mapper.update:
UPDATE admin_fit_analysis_memo
SET memo_type = #{memoType},
    content = #{content}
WHERE id = #{id}
  AND fit_analysis_id = #{fitAnalysisId}
  AND deleted_at IS NULL
  AND EXISTS (
      SELECT 1
      FROM fit_analysis active_fit
      INNER JOIN application_case active_case ON active_case.id = active_fit.application_case_id
      INNER JOIN users active_user ON active_user.id = active_case.user_id
      WHERE active_fit.id = #{fitAnalysisId}
        AND active_case.deleted_at IS NULL
        AND active_user.status != 'DELETED'
        AND active_user.deleted_at IS NULL
  )
